// Determine the 'after' epoch (seconds) for the Strava activities query.
// Strategy: use n8n workflow static data as the persistent 'last synced' marker.
// On the very first run (or a manual backfill) fall back to now - backfillDays.

const staticData = $getWorkflowStaticData('global');
const backfillDays = parseInt($('Config').item.json.backfillDays, 10) || 30;
const nowSec = Math.floor(Date.now() / 1000);
const fallback = nowSec - backfillDays * 24 * 60 * 60;

let after = staticData.lastSyncedEpoch;
if (typeof after !== 'number' || !after) {
  after = fallback;
}

// Carry the refreshed access token forward.
const accessToken = $('Refresh Strava token').item.json.access_token;

return [{ json: { after, accessToken } }];

// Build a Firestore REST document body (typed values) for one Strava run.
// The activity is available from the 'Split activities' node (the runQuery response
// items don't carry the original activity fields), so we look it back up by paired index.

const config = $('Config').first().json;
const uid = config.uid;

const results = [];

for (const item of $input.all()) {
  // Recover the original Strava activity for this item.
  // 'Check existing by stravaId' ran 1:1 off 'Only Runs', so pairedItem maps back.
  const activity = $('Only Runs').itemMatching(item.pairedItem?.item ?? 0).json;

  const movingTime = Number(activity.moving_time);           // seconds
  const distanceKm = Number(activity.distance) / 1000;       // Strava distance is metres
  const durationMin = Math.round(movingTime / 60);
  const avgPaceSecPerKm = distanceKm > 0 ? Math.round(movingTime / distanceKm) : null;

  // Strava sometimes omits average_heartrate (no HR sensor) -> null.
  const avgHr = (activity.average_heartrate === undefined || activity.average_heartrate === null)
    ? null
    : Number(activity.average_heartrate);

  // date = start_date_local as YYYY-MM-DD (already local to the athlete).
  const date = String(activity.start_date_local).slice(0, 10);

  const stravaId = String(activity.id);

  // Firestore REST typed-value document.
  const fields = {
    uid: { stringValue: uid },
    date: { stringValue: date },
    sport: { stringValue: 'running' },
    source: { stringValue: 'strava' },
    status: { stringValue: 'done' },
    durationMin: { integerValue: String(durationMin) },
    rpe: { nullValue: null },
    note: { nullValue: null },
    location: { nullValue: null },
    distanceKm: { doubleValue: distanceKm },
    avgPaceSecPerKm: avgPaceSecPerKm === null
      ? { nullValue: null }
      : { integerValue: String(avgPaceSecPerKm) },
    avgHr: avgHr === null ? { nullValue: null } : { doubleValue: avgHr },
    stravaId: { stringValue: stravaId },
    exercises: { arrayValue: { values: [] } },
    createdAt: { timestampValue: new Date().toISOString() },
    updatedAt: { timestampValue: new Date().toISOString() }
  };

  results.push({ json: { firestoreBody: { fields } } });
}

return results;

// Advance the 'last synced' marker so the next run only fetches newer activities.
// Use the newest start_date across ALL fetched runs (not just newly-created ones)
// so we still advance even when everything was already deduped.

const staticData = $getWorkflowStaticData('global');

let maxEpoch = staticData.lastSyncedEpoch || 0;
const runs = $('Only Runs').all();
for (const r of runs) {
  const startSec = Math.floor(new Date(r.json.start_date).getTime() / 1000);
  if (startSec > maxEpoch) maxEpoch = startSec;
}

if (maxEpoch > 0) {
  staticData.lastSyncedEpoch = maxEpoch;
}

return [{ json: { lastSyncedEpoch: staticData.lastSyncedEpoch, createdCount: $input.all().length } }];
